/** Pattern A — scroll tới field lỗi đầu tiên (data-testid `{prefix}-field-*`). */
export function scrollToFirstFieldError(testIdPrefix: string): void {
  document
    .querySelector<HTMLElement>(`[data-testid^="${testIdPrefix}-field-"]`)
    ?.scrollIntoView({ behavior: 'smooth', block: 'center' });
}
